UPDATE inbound_message
SET status = 'DELIVERING',
    delivery_id = #{deliveryId},
    lease_expires_at = #{leaseExpiresAt}
WHERE id = #{id}
  AND status = 'RECEIVED'

UPDATE inbound_message
SET lease_expires_at = #{leaseExpiresAt}
WHERE id = #{id}
  AND status = 'DELIVERING'

UPDATE inbound_message
SET status = 'CONSUMED'
WHERE id = #{id}
  AND delivery_id = #{deliveryId}
  AND status = 'DELIVERING'
